from heapq import heappush, heappop
from collections import Counter
from typing import List

def solve(nums: List[int], k: int) -> List[float]:
    n = len(nums)
    if k == 0 or n == 0:
        return []
    res = []
    to_remove = Counter()
    small = []   # 最大堆（存负数）
    large = []   # 最小堆

    def clean(heap, is_small):
        while heap:
            val = -heap[0] if is_small else heap[0]
            if to_remove[val] > 0:
                to_remove[val] -= 1
                heappop(heap)
            else:
                break

    def balance():
        # 调整使得 len(small) >= len(large) 且相差不超过1
        while len(small) > len(large) + 1:
            heappush(large, -heappop(small))
        while len(large) > len(small):
            heappush(small, -heappop(large))

    def get_median():
        clean(small, True)
        clean(large, False)
        if k % 2 == 1:
            return float(-small[0])
        else:
            return (-small[0] + large[0]) / 2.0

    # 初始窗口
    for i in range(k):
        heappush(small, -nums[i])
        if large and -small[0] > large[0]:
            top_small = -heappop(small)
            top_large = heappop(large)
            heappush(small, -top_large)
            heappush(large, top_small)
        if len(small) > len(large) + 1:
            heappush(large, -heappop(small))
        elif len(large) > len(small):
            heappush(small, -heappop(large))

    res.append(get_median())

    # 滑动窗口
    for i in range(k, n):
        left = nums[i - k]
        right = nums[i]
        to_remove[left] += 1

        if not small or right <= -small[0]:
            heappush(small, -right)
        else:
            heappush(large, right)

        balance()
        clean(small, True)
        clean(large, False)
        balance()
        clean(small, True)
        clean(large, False)

        res.append(get_median())

    return res
```

