def solve(deps: dict[str, list[str]], changed: list[str]) -> list[str]:
    # Build reverse dependency graph
    reverse_deps = {pkg: [] for pkg in deps}
    for pkg, dep_list in deps.items():
        for dep in dep_list:
            if dep not in reverse_deps:
                reverse_deps[dep] = []
            reverse_deps[dep].append(pkg)

    # Collect all packages that appear in deps or as dependencies
    all_pkgs = set(deps.keys())
    for dep_list in deps.values():
        all_pkgs.update(dep_list)

    # BFS/DFS to find all affected packages
    affected = set(changed)
    stack = list(changed)
    while stack:
        pkg = stack.pop()
        for dependent in reverse_deps.get(pkg, []):
            if dependent not in affected:
                affected.add(dependent)
                stack.append(dependent)

    return sorted(affected)
```

